module RefModule(CLK, LOAD, IN, OUT);input CLK, LOAD;
  input [15:0] IN;
  output reg [15:0] OUT;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (LOAD) begin
      OUT <= IN;
    end else begin
      OUT <= {OUT[14:0], 1'b0};
    end
  end

endmodule
